import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Mail, Lock, Eye, EyeOff } from 'lucide-react';
import { loginUser, clearError, clearSuccess } from 'host/authSlice';
import { useAppDispatch, useAppSelector } from 'host/hooks';

const Login = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { isLoading, error, success, user } = useAppSelector((state: any) => state.auth);

  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    remember: false,
  });

  useEffect(() => {
    return () => {
      dispatch(clearError());
      dispatch(clearSuccess());
    };
  }, [dispatch]);

  useEffect(() => {
    if (user && success) {
      // host can handle redirect if needed
    }
  }, [user, success]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;

    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));

    if (error) {
      dispatch(clearError());
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    dispatch(loginUser({ email: formData.email, password: formData.password }));
  };

  return (
    <div className="w-full max-w-xl rounded-[32px] bg-white/95 p-8 shadow-2xl backdrop-blur-md">
      <div className="text-center">
        <h3 className="text-5xl font-extrabold text-slate-950">
          Order<span className="text-cyan-600">Ease</span>
        </h3>
      </div>

      <div className="mt-8 grid grid-cols-2 border-b border-slate-300">
        <button
          className="border-b-4 border-cyan-600 pb-3 text-2xl font-semibold text-cyan-700"
        >
          Login
        </button>
        <button
          onClick={() => navigate('/signup')}
          className="pb-3 text-2xl font-semibold text-slate-800 transition hover:text-cyan-700"
        >
          Sign Up
        </button>
      </div>

      <div className="mt-8">
        <h4 className="text-center text-4xl font-bold text-slate-950">
          Sign In to Your Account
        </h4>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          {error && (
            <div className="rounded-2xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
              {error}
            </div>
          )}

          {success && (
            <div className="rounded-2xl border border-green-200 bg-green-50 p-4 text-sm text-green-700">
              {success}
            </div>
          )}

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Email Address
            </label>
            <div className="flex items-center rounded-2xl border border-slate-300 bg-white px-4 py-4">
              <Mail className="mr-3 h-5 w-5 text-slate-400" />
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="user@email.com"
                className="w-full bg-transparent text-lg text-slate-900 outline-none placeholder:text-slate-400"
                disabled={isLoading}
                required
              />
            </div>
          </div>

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Password
            </label>
            <div className="flex items-center rounded-2xl border border-slate-300 bg-white px-4 py-4">
              <Lock className="mr-3 h-5 w-5 text-slate-400" />
              <input
                type={showPassword ? 'text' : 'password'}
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="••••••••"
                className="w-full bg-transparent text-lg text-slate-900 outline-none placeholder:text-slate-400"
                disabled={isLoading}
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="ml-3 text-slate-400"
              >
                {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
              </button>
            </div>
          </div>

          <div className="flex items-center justify-between text-sm">
            <label className="flex items-center gap-3 text-slate-700">
              <input
                type="checkbox"
                name="remember"
                checked={formData.remember}
                onChange={handleChange}
                className="h-4 w-4 rounded border-slate-300"
              />
              Remember Me
            </label>

            <button
              type="button"
              className="font-medium text-cyan-700 hover:underline"
            >
              Forgot Password?
            </button>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full rounded-2xl bg-gradient-to-r from-blue-700 to-blue-500 py-4 text-xl font-bold text-white shadow-md transition hover:opacity-95 disabled:cursor-not-allowed disabled:opacity-70"
          >
            {isLoading ? 'Signing In...' : 'Log In'}
          </button>
        </form>

        <p className="mt-8 text-center text-lg text-slate-700">
          Don&apos;t have an account?{' '}
          <button
            onClick={() => navigate('/signup')}
            className="font-bold text-cyan-700"
          >
            Sign Up
          </button>
        </p>
      </div>
    </div>
  );
};

export default Login;